case class FetchRequest(url: String)
case class FetchResponse(url: String, status: Int, body: String)
case class ErrorResponse(error: String, url: String)
case class BatchFetchRequest(urls: List[String])
case class BatchFetchResponse(results: List[FetchResponse], errors: List[ErrorResponse])

object WebhookProxyService extends App {

  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

