  def fetchUrl(userUrl: String): Future[Either[ErrorResponse, FetchResponse]] = {
    val uri = try {
      Uri(userUrl)
    } catch {
      case e: Exception =>
        return Future.successful(Left(ErrorResponse(s"Invalid URL: ${e.getMessage}", userUrl)))
    }

    if (uri.scheme != "http" && uri.scheme != "https") {
      return Future.successful(Left(ErrorResponse("Only http and https schemes are allowed", userUrl)))
    }

    Http()
      .singleRequest(HttpRequest(uri = userUrl))
      .flatMap { response =>
        Unmarshal(response.entity).to[String].map { body =>
          Right(FetchResponse(
            url = userUrl,
            status = response.status.intValue(),
            body = body
          ))
        }
      }
      .recover {
        case ex: Exception =>
          Left(ErrorResponse(s"Failed to fetch URL: ${ex.getMessage}", userUrl))
      }
  }

  val route =
    pathPrefix("api") {
      concat(
        path("fetch") {
          post {
            entity(as[FetchRequest]) { request =>
              val resultFuture = fetchUrl(request.url)
              onComplete(resultFuture) {
                case Success(Right(fetchResponse)) =>
                  complete(StatusCodes.OK, fetchResponse)
                case Success(Left(errorResponse)) =>
                  complete(StatusCodes.BadRequest, errorResponse)
                case Failure(ex) =>
                  complete(StatusCodes.InternalServerError, ErrorResponse(ex.getMessage, request.url))
              }
            }
          }
