                request.urls.map(fetchUrl)

              val aggregated: Future[List[Either[ErrorResponse, FetchResponse]]] =
                Future.sequence(futures)

              onComplete(aggregated) {
                case Success(results) =>
                  val successes = results.collect { case Right(r) => r }
                  val errors = results.collect { case Left(e) => e }
                  complete(StatusCodes.OK, BatchFetchResponse(successes, errors))
                case Failure(ex) =>
                  complete(
                    StatusCodes.InternalServerError,
                    ErrorResponse(s"Batch processing failed: ${ex.getMessage}", "")
